$newEntries = @(
'{"id":1,"key":"signpair.saturn_uranus.taurus_aries","type":"sign_pair_combo","short":"Земная дисциплина встречает огненный прорыв — устойчивость, зажжённая молнией","full":"Сатурн в Тельце строит медленно и надёжно, Уран в Овне взрывает инерцию дерзким импульсом. Вместе они создают редкое качество: умение стартовать из полного покоя. Ты не суетишься перед рывком — ты накапливаешь энергию как сжатая пружина, и когда бьёшь, земля дрожит.","tags":["устойчивость","импульс","пружина"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":2,"key":"signpair.saturn_uranus.taurus_aries","type":"sign_pair_combo","short":"Терпеливый строитель, вооружённый электрическим копьём — фундамент для прорыва","full":"Телец с Сатурном знает: настоящие перемены требуют основания. Уран в Овне даёт искру. Ты не бросаешься в бой сломя голову — ты готовишь плацдарм, а затем наносишь удар такой силы, что привычный ландшафт меняется навсегда. Твоя медлительность — это стратегия, а не слабость.","tags":["стратегия","подготовка","удар"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":3,"key":"signpair.saturn_uranus.taurus_aries","type":"sign_pair_combo","short":"Дисциплина земли укрощает уранический огонь — вулкан, просыпающийся по расписанию","full":"Ты не взрываешься спонтанно — ты извергаешься по плану. Сатурн в Тельце структурирует саму стихию материи, Уран в Овне даёт первобытный жар. Когда ты наконец действуешь, твоя сила не рассеивается впустую — она точно направлена и невероятно мощна.","tags":["вулкан","мощь","план"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":4,"key":"signpair.saturn_uranus.taurus_aries","type":"sign_pair_combo","short":"Структурированная плоть встречает электрический дух — тело, ставшее проводником","full":"Сатурн в Тельце даёт телесную дисциплину, Уран в Овне — духовный прорыв. Ты не разделяешь физическое и ментальное: твоё тело — точный инструмент, а твои инсайты воплощены в действии. Движение становится молитвой, работа — медитацией, сопротивление материалов — источником озарений.","tags":["тело","проводник","воплощение"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":1,"key":"signpair.saturn_uranus.taurus_taurus","type":"sign_pair_combo","short":"Двойная земля под ураническим напряжением — тектонический сдвиг в самом основании","full":"Сатурн и Уран в Тельце — это землетрясение в мире форм. Дисциплина встречает собственный бунт, стабильность парадоксально обновляет себя. Ты перестраиваешь фундамент, не разрушая здания; меняешь ценности, не предавая себя; растёшь не вверх, а вглубь, где никто не видит, но все чувствуют.","tags":["фундамент","сдвиг","глубина"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":2,"key":"signpair.saturn_uranus.taurus_taurus","type":"sign_pair_combo","short":"Структура, взламывающая саму себя — алхимия материи, достигшая предела","full":"Когда сатурнианский Телец встречает уранический — материя начинает мыслить. Ты не просто владеешь ресурсами — ты переосмысляешь само понятие владения. Твоя собственность служит свободе, твои привычки — трамплин, твоё тело — лаборатория, где рождается новый способ быть в мире.","tags":["материя","владение","лаборатория"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":3,"key":"signpair.saturn_uranus.taurus_taurus","type":"sign_pair_combo","short":"Дисциплина ценностей встречает электрический переворот — революция в кошельке","full":"Твои отношения с деньгами — не жадность и не расточительство, а третий путь. Сатурн даёт финансовую зрелость, Уран переизобретает источники дохода. Ты не копишь на чёрный день — ты инвестируешь в прорыв; не экономишь на мелочах — ты создаёшь ценность там, где другие видят расходы.","tags":["финансы","ценность","инвестиции"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":4,"key":"signpair.saturn_uranus.taurus_taurus","type":"sign_pair_combo","short":"Терпеливая плоть, пронизанная гениальностью — тело, знающее путь","full":"Ты слышишь мудрость тела громче, чем голоса извне. Сатурн даёт режим и выдержку, Уран — внезапные телесные инсайты. Твоя соматика — не фитнес-рутина, а путь познания. Через ощущения ты выходишь на прозрения, через физический труд — на философские откровения.","tags":["соматика","познание","мудрость"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":1,"key":"signpair.saturn_uranus.taurus_gemini","type":"sign_pair_combo","short":"Земная дисциплина питает ментальную молнию — слово, обретающее вес","full":"Сатурн в Тельце даёт основательность, Уран в Близнецах — скорость мысли. Ты не просто болтаешь — каждое твоё слово выверено весом опыта и заряжено неожиданным ракурсом. Твоя речь меняет реальность не громкостью, а плотностью смысла, посеянного в плодородную почву.","tags":["слово","плотность","смысл"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":2,"key":"signpair.saturn_uranus.taurus_gemini","type":"sign_pair_combo","short":"Структурированное терпение встречает электрический интеллект — мыслитель-ремесленник","full":"Ты думаешь руками. Сатурн в Тельце даёт мастерство воплощения, Уран в Близнецах — ментальные вспышки. Твои идеи не витают в облаках — они немедленно пробуются на ощупь, на вкус, на прочность. Ты — изобретатель, чей гараж полон работающих прототипов, а не чертежей.","tags":["ремесло","прототипы","мастерство"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":3,"key":"signpair.saturn_uranus.taurus_gemini","type":"sign_pair_combo","short":"Дисциплина формы отливает электрическую мысль — гений, укоренённый в практике","full":"Близнецы с Ураном генерируют потоки идей; Телец с Сатурном выбирает одну и доводит до совершенства. Ты — редкий тип: генератор прорывов, который знает, как их монетизировать, упаковать, сделать осязаемыми. Твоя гениальность не пугает, а кормит.","tags":["монетизация","упаковка","практика"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":4,"key":"signpair.saturn_uranus.taurus_gemini","type":"sign_pair_combo","short":"Земное постоянство электризует ментальное поле — сад идей, цветущий круглый год","full":"Твой ум — не фейерверк, а оранжерея. Сатурн в Тельце создаёт идеальные условия для роста мыслей, Уран в Близнецах даёт неожиданные гибриды и мутации. Ты культивируешь интеллект как садовник: терпеливо, с любовью к процессу, и урожай всегда удивляет разнообразием.","tags":["культивация","сад","урожай"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":1,"key":"signpair.saturn_uranus.taurus_cancer","type":"sign_pair_combo","short":"Земная дисциплина встречает эмоциональный прорыв — дом, ставший лабораторией","full":"Сатурн в Тельце строит надёжные стены, Уран в Раке взламывает фамильные сценарии. Ты создаёшь пространство, где безопасность не душит, а питает смелость. Твой дом — не крепость от мира, а база для исследования самых глубоких слоёв себя и отношений.","tags":["дом","безопасность","исследование"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":2,"key":"signpair.saturn_uranus.taurus_cancer","type":"sign_pair_combo","short":"Структурированная забота электризует род — корни, ставшие крыльями","full":"Ты не обрубаешь прошлое и не застреваешь в нём — ты перепрошиваешь родовые коды. Сатурн в Тельце даёт уважение к традиции, Уран в Раке — смелость переписать наследство. Ты берёшь от предков лучшее и добавляешь то, чего им не хватало: свободу быть собой.","tags":["род","традиция","перепрошивка"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":3,"key":"signpair.saturn_uranus.taurus_cancer","type":"sign_pair_combo","short":"Дисциплинированная нежность встречает электрическую эмпатию — защитник без доспехов","full":"Твоя забота не удушает — она освобождает. Сатурн в Тельце даёт устойчивость в чувствах, Уран в Раке — способность мгновенно считывать эмоциональное поле и менять его. Ты — якорь и молния одновременно: рядом с тобой спокойно, но никогда не скучно.","tags":["эмпатия","якорь","освобождение"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":4,"key":"signpair.saturn_uranus.taurus_cancer","type":"sign_pair_combo","short":"Земля дисциплины питает электрический очаг — уют, заряженный прорывом","full":"Твой быт — не рутина, а ритуал силы. Сатурн в Тельце превращает повседневность в опору, Уран в Раке вносит в неё элемент священного безумия. Завтрак может стать инсайтом, вечерний разговор — порталом в новую реальность. Ты умеешь делать обыденное магическим, не теряя почвы.","tags":["ритуал","уют","магия"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":1,"key":"signpair.saturn_uranus.taurus_leo","type":"sign_pair_combo","short":"Земная дисциплина сияет электрическим светом — творец, чьё искусство можно потрогать","full":"Сатурн в Тельце даёт мастерство формы, Уран во Льве — гениальное самовыражение. Ты не просто творишь — ты создаёшь артефакты. Твоё искусство осязаемо, твоя харизма имеет вес, твоя щедрость структурирована так, что каждый дар меняет жизнь получателя необратимо.","tags":["артефакт","искусство","харизма"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":2,"key":"signpair.saturn_uranus.taurus_leo","type":"sign_pair_combo","short":"Структурированное терпение встречает электрическое сияние — король, знающий цену","full":"Лев с Ураном хочет блистать немедленно; Телец с Сатурном знает, что настоящее сияние требует времени. Ты не гонишься за аплодисментами — ты растишь величие как дерево: медленно, неотвратимо. Когда ты выходишь на сцену, зал замирает не от шума, а от присутствия.","tags":["величие","присутствие","время"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":3,"key":"signpair.saturn_uranus.taurus_leo","type":"sign_pair_combo","short":"Дисциплина материи облекает электрический дар — щедрость, не знающая потерь","full":"Ты даёшь не из избытка — ты даёшь из структуры. Сатурн в Тельце выстроил систему, внутри которой щедрость Урана во Льве не истощает, а приумножает. Каждый подарок возвращается сторицей не по волшебству, а потому что ты вложил в него не только ресурс, но и гениальность.","tags":["щедрость","система","приумножение"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":4,"key":"signpair.saturn_uranus.taurus_leo","type":"sign_pair_combo","short":"Плодородная почва для электрического солнца — урожай харизмы, зреющий годами","full":"Твоя привлекательность не вспыхивает и гаснет — она нарастает как многолетнее растение. Сатурн в Тельце даёт выдержку стиля, Уран во Льве — неповторимый шарм. С возрастом ты становишься только ярче, потому что твой свет питается не молодостью, а глубиной прожитого.","tags":["шарм","стиль","зрелость"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":1,"key":"signpair.saturn_uranus.taurus_virgo","type":"sign_pair_combo","short":"Земная дисциплина встречает электрический анализ — перфекционист, взламывающий систему","full":"Два знака, управляемых Меркурием по-разному: Телец через форму, Дева через деталь. Сатурн даёт терпение ремесленника, Уран — гениальный сбой в протоколе. Ты находишь ошибки не для критики, а для прорыва. Каждый твой баг-репорт — это чертёж новой реальности.","tags":["перфекционизм","анализ","чертёж"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":2,"key":"signpair.saturn_uranus.taurus_virgo","type":"sign_pair_combo","short":"Структурированная почва для электрической точности — метод, растущий из практики","full":"Твои методики не из учебников — они выращены. Сатурн в Тельце культивирует подходы годами, Уран в Деве приносит озарения, совершенствующие процесс. Ты не просто работаешь хорошо — ты переизобретаешь саму технологию работы, делая её одновременно надёжной и революционной.","tags":["метод","технология","надёжность"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":3,"key":"signpair.saturn_uranus.taurus_virgo","type":"sign_pair_combo","short":"Дисциплина материи оттачивает электрическую деталь — мастер невидимых шедевров","full":"Ты совершенствуешь то, что другие даже не замечают — и в этом твоя сила. Сатурн в Тельце даёт осязаемый результат, Уран в Деве — микроскопические улучшения с макропоследствиями. Твой труд тих, но мир меняется от него сильнее, чем от громких манифестов.","tags":["незаметность","влияние","совершенство"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":4,"key":"signpair.saturn_uranus.taurus_virgo","type":"sign_pair_combo","short":"Почва и скальпель — земная выдержка с электрической хирургией","full":"Ты режешь точно и заживляешь надёжно. Сатурн в Тельце даёт ресурс для восстановления, Уран в Деве — радикально новые методы исцеления. Твоя забота о здоровье — не ипохондрия, а инженерия тела. Ты чинишь организмы и системы с одинаковым мастерством.","tags":["здоровье","исцеление","инженерия"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":1,"key":"signpair.saturn_uranus.taurus_libra","type":"sign_pair_combo","short":"Земная дисциплина встречает электрическую гармонию — архитектор справедливых миров","full":"Сатурн в Тельце строит прочный мир, Уран в Весах взламывает несправедливые структуры. Ты не просто критикуешь дисбаланс — ты возводишь альтернативу из камня, а не из лозунгов. Твоя справедливость осязаема: она в контрактах, интерьерах, распределении благ.","tags":["справедливость","строительство","баланс"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":2,"key":"signpair.saturn_uranus.taurus_libra","type":"sign_pair_combo","short":"Структурированная красота электризует союзы — партнёрство с прочным фундаментом","full":"Твои отношения не рассыпаются от ветра перемен. Сатурн в Тельце даёт надёжность, Уран в Весах — постоянное обновление формы союза. Ты умеешь быть верным, не становясь скучным; свободным, не становясь ненадёжным. Твоя любовь — архитектура, а не эмоциональные качели.","tags":["союз","верность","обновление"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":3,"key":"signpair.saturn_uranus.taurus_libra","type":"sign_pair_combo","short":"Дисциплина формы находит свободу в эстетике — красота, ставшая оружием","full":"Ты знаешь: прекрасное не просто радует глаз, оно перепрограммирует сознание. Сатурн в Тельце даёт чувство пропорции, Уран в Весах — гениальные эстетические решения. Ты создаёшь среду, которая сама по себе является манифестом — интерьер, наряд, образ, меняющие правила.","tags":["эстетика","среда","влияние"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":4,"key":"signpair.saturn_uranus.taurus_libra","type":"sign_pair_combo","short":"Терпеливая гармония, пронзённая электрическим чутьём — дипломат с золотыми руками","full":"Ты улаживаешь конфликты не словами, а действиями. Сатурн в Тельце даёт умение создать ценность, которую невозможно отвергнуть; Уран в Весах находит неожиданные точки согласия. Твой компромисс — не уступка, а изобретение третьего варианта, выгодного всем.","tags":["дипломатия","ценность","компромисс"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":1,"key":"signpair.saturn_uranus.taurus_scorpio","type":"sign_pair_combo","short":"Земная дисциплина встречает электрическую бездну — кладоискатель в глубинах души","full":"Сатурн в Тельце даёт устойчивость в материальном, Уран в Скорпионе взрывает подземные истины. Ты не боишься копать там, где другие пугаются. Твоя добыча — не золото, а знание; твои инвестиции — в трансформацию, которая окупается не деньгами, а перерождением.","tags":["глубина","знание","трансформация"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":2,"key":"signpair.saturn_uranus.taurus_scorpio","type":"sign_pair_combo","short":"Структурированная плоть пронзает электрическую тьму — алхимик ресурсов","full":"Ты превращаешь кризисы в капитал. Сатурн в Тельце знает цену всему, Уран в Скорпионе находит сокровища там, где другие видят руины. Твоя способность извлекать ценность из потерь граничит с магией, но на деле это дисциплина видеть возможности в самых тёмных углах.","tags":["ресурсы","кризис","алхимия"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":3,"key":"signpair.saturn_uranus.taurus_scorpio","type":"sign_pair_combo","short":"Дисциплинированная страсть укрощает электрическую одержимость — власть без разрушения","full":"Ты обладаешь силой, которая не ломает, а строит. Сатурн в Тельце даёт контроль над желаниями, Уран в Скорпионе освобождает от компульсивных паттернов. Твоя страсть — не пожар, а геотермальная станция: горячо, стабильно и питает целый город.","tags":["страсть","контроль","стабильность"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":4,"key":"signpair.saturn_uranus.taurus_scorpio","type":"sign_pair_combo","short":"Земля, вскрытая электрическим плугом — возрождение из глубочайшего кризиса","full":"Ты проходишь сквозь смерть и возрождение не как драму, а как технологический процесс. Сатурн в Тельце даёт ритуал и структуру трансформации, Уран в Скорпионе взрывает старые формы одним ударом. Ты знаешь: чтобы вырастить новое, нужно сначала глубоко вспахать.","tags":["возрождение","ритуал","глубина"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":1,"key":"signpair.saturn_uranus.taurus_sagittarius","type":"sign_pair_combo","short":"Земная дисциплина встречает электрическое видение — путешественник с картой сокровищ","full":"Сатурн в Тельце даёт выносливость в долгом пути, Уран в Стрельце — компас, указывающий туда, где ещё никто не бывал. Ты не бродишь бесцельно — каждое твоё путешествие имеет структуру, но маршрут всегда удивляет. Ты открываешь миры, заземляя их в ощущениях.","tags":["путешествие","выносливость","открытие"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":2,"key":"signpair.saturn_uranus.taurus_sagittarius","type":"sign_pair_combo","short":"Структурированная почва для электрической философии — мудрец, проверяющий истину телом","full":"Ты не веришь на слово — ты пробуешь. Сатурн в Тельце требует физического доказательства, Уран в Стрельце приносит откровения, которые ты немедленно тестируешь на практике. Твоя философия — не абстракция, а выжимка из прожитого опыта, плотная как хорошая земля.","tags":["практика","философия","опыт"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":3,"key":"signpair.saturn_uranus.taurus_sagittarius","type":"sign_pair_combo","short":"Дисциплина материи расширяет электрические горизонты — строитель межкультурных мостов","full":"Ты соединяешь миры не словами, а делами. Сатурн в Тельце возводит реальную инфраструктуру — от бизнеса до искусства, Уран в Стрельце видит глобальную картину. Твои проекты пересекают границы, потому что стоят на земле, а не на идеологии.","tags":["глобальность","инфраструктура","мосты"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":4,"key":"signpair.saturn_uranus.taurus_sagittarius","type":"sign_pair_combo","short":"Терпеливая экспансия, заряженная электрическим смыслом — богатство как следствие пути","full":"Ты не гонишься за богатством — оно приходит как побочный эффект твоего путешествия. Сатурн в Тельце накапливает ресурсы естественно, Уран в Стрельце открывает источники изобилия там, где другие проходят мимо. Твой достаток — не цель, а топливо для следующих открытий.","tags":["изобилие","путь","естественность"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":1,"key":"signpair.saturn_uranus.taurus_capricorn","type":"sign_pair_combo","short":"Земная дисциплина на уранической вершине — архитектор новой власти","full":"Сатурн управляет обоими знаками — двойная доза структуры на земной почве. Уран в Козероге взламывает иерархии. Ты строишь империи не ради контроля, а ради свободы многих. Твоя власть — это платформа, на которой другие могут расти, а не пирамида, где они ютятся у подножия.","tags":["власть","платформа","империя"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":2,"key":"signpair.saturn_uranus.taurus_capricorn","type":"sign_pair_combo","short":"Структурированная почва электризует иерархии — строитель пост-капитализма","full":"Ты переизобретаешь экономику снизу. Сатурн в Тельце даёт материальную базу, Сатурн в Козероге — системное мышление, Уран — прорывную модель. Твои бизнесы, проекты, сообщества работают по законам, которые мир освоит через двадцать лет. Ты не ждёшь будущего — ты его закладываешь.","tags":["экономика","модель","опережение"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":3,"key":"signpair.saturn_uranus.taurus_capricorn","type":"sign_pair_combo","short":"Дисциплина формы штурмует электрические вершины — карьера, высеченная из прорывов","full":"Твой профессиональный путь не линеен — он скачкообразен, но каждый скачок подготовлен годами. Сатурн в Тельце накапливает компетенции, Уран в Козероге взрывает карьерные тупики. Ты не карабкаешься по лестнице — ты телепортируешься на следующий уровень, когда готов.","tags":["карьера","скачок","готовность"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":4,"key":"signpair.saturn_uranus.taurus_capricorn","type":"sign_pair_combo","short":"Плодородная земля на каменной вершине — наследие, которое кормит поколения","full":"Ты строишь не просто состояние — ты создаёшь экосистему. Сатурн в Тельце даёт ресурсную базу, Сатурн в Козероге — вечную структуру, Уран — инновационный импульс. Твоё наследие — не застывший монумент, а живой организм, продолжающий эволюционировать после тебя.","tags":["наследие","экосистема","эволюция"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":1,"key":"signpair.saturn_uranus.taurus_aquarius","type":"sign_pair_combo","short":"Земная дисциплина в электрическом доме — свобода, имеющая прочный фундамент","full":"Сатурн в Тельце даёт материальную независимость, Уран в Водолее — в своём доме, максимально силён. Ты не просто мечтаешь о свободе — ты выстроил систему, которая её обеспечивает. Твоя автономия не от мира, а внутри него: ты свободен, потому что умеешь создавать ценность на своих условиях.","tags":["автономия","независимость","система"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":2,"key":"signpair.saturn_uranus.taurus_aquarius","type":"sign_pair_combo","short":"Структурированная щедрость электризует сообщества — меценат нового типа","full":"Ты поддерживаешь не проекты — ты инвестируешь в прорывы. Сатурн в Тельце даёт ресурсы, Уран в Водолее — чутьё на гениальное. Твоя помощь не создаёт зависимости — она запускает цепные реакции. Каждый, кого ты поддержал, начинает поддерживать других.","tags":["меценатство","инвестиции","цепная реакция"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":3,"key":"signpair.saturn_uranus.taurus_aquarius","type":"sign_pair_combo","short":"Дисциплина почвы встречает электрическую утопию — инженер сбывающихся пророчеств","full":"Твои прогнозы сбываются не потому, что ты ясновидящий, а потому что ты их строишь. Сатурн в Тельце даёт воплощение, Уран в Водолее — видение. Ты не предсказываешь тренды — ты их создаёшь, закладывая материальный фундамент под то, что пока существует лишь как идея.","tags":["прогноз","тренд","воплощение"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":4,"key":"signpair.saturn_uranus.taurus_aquarius","type":"sign_pair_combo","short":"Терпеливая революция, укоренённая в ценностях — бунт, ставший образом жизни","full":"Ты не бунтуешь разово — ты живёшь альтернативой каждый день. Сатурн в Тельце встроил свободу в быт, в питание, в заработок. Твой образ жизни — манифест, который не нужно озвучивать. Люди, глядя на тебя, понимают: можно иначе, и это «иначе» работает.","tags":["образ жизни","манифест","альтернатива"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":1,"key":"signpair.saturn_uranus.taurus_pisces","type":"sign_pair_combo","short":"Земная дисциплина встречает электрический океан — сад, растущий из хаоса","full":"Сатурн в Тельце даёт умение культивировать, Уран в Рыбах — доступ к безграничному полю идей. Ты не тонешь в возможностях — ты выбираешь семена и выращиваешь из них реальность. Твоя интуиция работает как ирригационная система, питая самые смелые ростки и отсекая сорняки.","tags":["сад","идеи","интуиция"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":2,"key":"signpair.saturn_uranus.taurus_pisces","type":"sign_pair_combo","short":"Структурированная плоть ныряет в электрическое бессознательное — тело как оракул","full":"Твоё тело знает ответы раньше, чем ум формулирует вопрос. Сатурн в Тельце даёт телесную осознанность, Уран в Рыбах подключает к коллективному бессознательному. Ты чувствуешь вибрации реальности кожей, и эти сигналы никогда не врут — они просто требуют зрелости для расшифровки.","tags":["тело","оракул","бессознательное"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":3,"key":"signpair.saturn_uranus.taurus_pisces","type":"sign_pair_combo","short":"Дисциплина материи плавит электрические грёзы — ремесленник сновидений","full":"Ты не просто мечтаешь — ты изготавливаешь сны в материале. Сатурн в Тельце даёт ремесленные навыки, Уран в Рыбах — космическое воображение. Твоя работа — мост между мирами: ты берёшь образ из глубин психики и превращаешь его в предмет, которым можно пользоваться.","tags":["сновидения","ремесло","мост"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}',
'{"id":4,"key":"signpair.saturn_uranus.taurus_pisces","type":"sign_pair_combo","short":"Плодородная земля, напоённая электрическим океаном — изобилие как духовная практика","full":"Ты достиг того уровня, где материальное и духовное не конфликтуют. Сатурн в Тельце даёт достаток, Уран в Рыбах — понимание, что всё едино. Твоё богатство течёт сквозь тебя, а не застревает в тебе. Ты — проводник изобилия, которое приходит не из жадности, а из сонастройки с потоком.","tags":["изобилие","поток","сонастройка"],"audience":"general","lang":"ru","version":"1.0","needs_review":false}'
)

# Read current file, strip trailing ], append entries, close
$path = "stellar/data/generated/sign_pair_combos/saturn_uranus.json"
$content = Get-Content $path -Raw -Encoding UTF8
$content = $content.TrimEnd()
# Remove trailing ] and any whitespace before it
$content = $content -replace '\s*\]\s*$', ''
